import os
import subprocess

task_id = "a3fbeb63-0e8c-4a11-bff6-0e3b484c3e9c"

print(f"Searching for files containing: {task_id}")

# Use find command to search more comprehensively
try:
    result = subprocess.run(['find', '/', '-name', f'*{task_id}*', '-type', 'f'], 
                          capture_output=True, text=True, timeout=10)
    if result.stdout.strip():
        print("Found files:")
        print(result.stdout)
    else:
        print("No files found with task ID in name")
except Exception as e:
    print(f"Find command failed: {e}")

